class TestSemaphore {
  #available: number;
  #queue: Array<(release: () => void) => void> = [];
  constructor(max: number) {
    this.#available = Math.max(1, max);
  }
  async acquire(): Promise<() => void> {
    if (this.#available > 0) {
      this.#available--;
      return this.#release;
    }
    return await new Promise<() => void>((resolve) => {
      this.#queue.push(resolve);
    });
  }
  #release = () => {
    let next = this.#queue.shift();
    if (next) {
      next(this.#release);
      return;
    }
    this.#available++;
  };
}
